cssRules.css:
--btn-bg: linear-gradient(180deg,
      color-mix(in oklab, var(--accent) 92%, #fff 10%),
      color-mix(in oklab, var(--accent) 86%, #000 4%)); --btn-ink: #ffffff; inline-size: 100%; padding: 12px 16px; border: 0px; border-radius: 25px; color: var(--btn-ink); background: var(--btn-bg); position: relative; box-shadow: inset 0 1px 0 0 rgba(255,255,255,.35),0 8px 22px -10px color-mix(in oklab,var(--accent) 40%,transparent),0 2px 6px -2px rgba(0,0,0,.35); transform: translateZ(0px); transition: transform 60ms, box-shadow 0.18s, filter 0.18s; cursor: pointer; font-size: 16px; display: flex; align-items: center; justify-content: center; height: 45px;
